import { isArray } from '../../utils/zcutils.js';

/*
 * n - selector name
 * v - selector value
 * p - parser
 */
function _loopParser(n, v, p) {
    var _s;
    for (var _key in p) {
        if (p.hasOwnProperty(_key)) {
            if (_key === n && p[n] === v) {
                return p;
            }
            var _val = p[_key];
            if (isArray(_val)) {
                for (var i = 0; i < _val.length; i++) {
                    _s = _loopParser(n, v, _val[i]);
                    if (_s) {
                        return _s;
                    }
                }
            }
        }
    }
}

/*
 * n - selector name - name,mark,selector
 * v - selector value
 * parser.select - selects the first object with the given details.
 */
export function select(n, v) {
    if(isArray(n)){
        this.selection = [];
        n.map((d,i)=>{
            this.selection.push(_loopParser(d, v[i], this.parser));
        })
    }else{
        this.selection = _loopParser(n, v, this.parser);
    }
    
    return this;
}
